mapper.select:
SELECT tnc.id, tnc.note_id, tnc.chunk_text, tnc.chunk_index, tnc.location_keywords AS locationKeywordsStr, tnc.content_type AS contentType, tnc.created_at, tn.title AS note_title, ts_rank(tnc.chunk_tsvector, plainto_tsquery('simple', #{queryText})) AS similarity FROM travel_note_chunks tnc JOIN user_travel_notes tn ON tnc.note_id = tn.id WHERE tn.status = 'active' AND tnc.chunk_tsvector @@ plainto_tsquery('simple', #{queryText})
AND tnc.location_keywords LIKE CONCAT('%', #{locationKeyword}, '%')
ORDER BY similarity DESC LIMIT #{limit}

SELECT tnc.id, tnc.note_id, tnc.chunk_text, tnc.chunk_index, tnc.location_keywords AS locationKeywordsStr, tnc.content_type AS contentType, tnc.created_at, tn.title AS note_title, 1 - (tnc.embedding <=> #{embedding}::vector) AS similarity FROM travel_note_chunks tnc JOIN user_travel_notes tn ON tnc.note_id = tn.id WHERE tn.status = 'active'
AND tnc.location_keywords LIKE CONCAT('%', #{locationKeyword}, '%')
ORDER BY tnc.embedding <=> #{embedding}::vector LIMIT #{limit}

SELECT tnc.id, tnc.note_id, tnc.chunk_text, tnc.chunk_index, tnc.content_type AS contentType, tnc.created_at FROM travel_note_chunks tnc WHERE tnc.note_id IN
#{id}
ORDER BY RANDOM() LIMIT #{limit}
